const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');
const libxmljs = require('libxmljs');

const app = express();
const upload = multer({ dest: 'uploads/' });

app.post('/upload', upload.single('xmlFile'), (req, res) => {
  const xmlFilePath = req.file.path;

  fs.readFile(xmlFilePath, (err, data) => {
    if (err) {
      return res.status(500).send('Error reading file');
    }

    try {
      const xmlDoc = libxmljs.parseXml(data);
      const configObject = parseXMLToConfig(xmlDoc);

      // Process the configuration object as needed
      console.log(configObject);

      res.send('XML processed successfully');
    } catch (error) {
      return res.status(400).send('Error parsing XML');
    }
  });
});

function parseXMLToConfig(xmlDoc) {
  const config = {};

  // Extract configuration settings from the XML document
  // Example: Assuming the XML has a root element 'configuration' with child elements for different settings
  xmlDoc.root().childNodes().forEach(child => {
    if (child.type() === 'element') {
      config[child.name()] = child.text();
    }
  });

  return config;
}

app.listen(3000, () => {
  console.log('Server is running on port 3000');
});